   279	function mergePostUnitHooks(
   280	  base?: PostUnitHookConfig[],
   281	  override?: PostUnitHookConfig[],
   282	): PostUnitHookConfig[] | undefined {
   283	  if (!base?.length && !override?.length) return undefined;
   284	  const merged = [...(base ?? [])];
   285	  for (const hook of override ?? []) {
   286	    // Override hooks with same name replace base hooks
   287	    const idx = merged.findIndex(h => h.name === hook.name);
   288	    if (idx >= 0) {
   289	      merged[idx] = hook;
   290	    } else {
   291	      merged.push(hook);
   292	    }
   293	  }
   294	  return merged.length > 0 ? merged : undefined;
