   315	
   316	export function renderPreferencesForSystemPrompt(preferences: GSDPreferences, resolutions?: Map<string, SkillResolution>): string {
   317	  const validated = validatePreferences(preferences);
   318	  const lines: string[] = ["## GSD Skill Preferences"];
   319	
   320	  if (validated.errors.length > 0) {
   321	    lines.push("- Validation: some preference values were ignored because they were invalid.");
   322	  }
   323	  for (const warning of validated.warnings) {
   324	    lines.push(`- Deprecation: ${warning}`);
   325	  }
   326	
   327	  preferences = validated.preferences;
   328	
   329	  lines.push(
   330	    "- Treat these as explicit skill-selection policy for GSD work.",
   331	    "- If a listed skill exists and is relevant, load and follow it instead of treating it as a vague suggestion.",
   332	    "- Current user instructions still override these defaults.",
   333	  );
   334	
   335	  const fmt = (ref: string) => resolutions ? formatSkillRef(ref, resolutions) : ref;
   336	
   337	  if (preferences.always_use_skills && preferences.always_use_skills.length > 0) {
   338	    lines.push("- Always use these skills when relevant:");
   339	    for (const skill of preferences.always_use_skills) {
   340	      lines.push(`  - ${fmt(skill)}`);
   341	    }
   342	  }
   343	
   344	  if (preferences.prefer_skills && preferences.prefer_skills.length > 0) {
   345	    lines.push("- Prefer these skills when relevant:");
   346	    for (const skill of preferences.prefer_skills) {
   347	      lines.push(`  - ${fmt(skill)}`);
   348	    }
   349	  }
   350	
   351	  if (preferences.avoid_skills && preferences.avoid_skills.length > 0) {
   352	    lines.push("- Avoid these skills unless clearly needed:");
   353	    for (const skill of preferences.avoid_skills) {
   354	      lines.push(`  - ${fmt(skill)}`);
   355	    }
   356	  }
   357	
   358	  if (preferences.skill_rules && preferences.skill_rules.length > 0) {
   359	    lines.push("- Situational rules:");
   360	    for (const rule of preferences.skill_rules) {
   361	      lines.push(`  - When ${rule.when}:`);
   362	      if (rule.use && rule.use.length > 0) {
   363	        lines.push(`    - use: ${rule.use.map(fmt).join(", ")}`);
   364	      }
   365	      if (rule.prefer && rule.prefer.length > 0) {
   366	        lines.push(`    - prefer: ${rule.prefer.map(fmt).join(", ")}`);
   367	      }
   368	      if (rule.avoid && rule.avoid.length > 0) {
   369	        lines.push(`    - avoid: ${rule.avoid.map(fmt).join(", ")}`);
   370	      }
   371	    }
   372	  }
   373	
   374	  if (preferences.custom_instructions && preferences.custom_instructions.length > 0) {
   375	    lines.push("- Additional instructions:");
   376	    for (const instruction of preferences.custom_instructions) {
   377	      lines.push(`  - ${instruction}`);
   378	    }
   379	  }
   380	
   381	  return lines.join("\n");
   382	}
