   390	export function resolvePostUnitHooks(): PostUnitHookConfig[] {
   391	  const prefs = loadEffectiveGSDPreferences();
   392	  return (prefs?.preferences.post_unit_hooks ?? [])
   393	    .filter(h => h.enabled !== false);
   394	}
