   396	/**
   397	 * Resolve enabled pre-dispatch hooks from effective preferences.
   398	 * Returns an empty array when no hooks are configured.
   399	 */
   400	export function resolvePreDispatchHooks(): PreDispatchHookConfig[] {
   401	  const prefs = loadEffectiveGSDPreferences();
   402	  return (prefs?.preferences.pre_dispatch_hooks ?? [])
   403	    .filter(h => h.enabled !== false);
   404	}
