   407	
   408	/**
   409	 * Resolve the effective git isolation mode from preferences.
   410	 * Returns "none" (default), "worktree", or "branch".
   411	 *
   412	 * Default is "none" so GSD works out of the box without preferences.md.
   413	 * Worktree isolation requires explicit opt-in because it depends on git
   414	 * branch infrastructure that must be set up before use.
   415	 */
   416	export function getIsolationMode(): "none" | "worktree" | "branch" {
   417	  const prefs = loadEffectiveGSDPreferences()?.preferences?.git;
   418	  if (prefs?.isolation === "worktree") return "worktree";
   419	  if (prefs?.isolation === "branch") return "branch";
   420	  return "none"; // default — no isolation, work on current branch
   421	}
   422	
   423	export function resolveParallelConfig(prefs: GSDPreferences | undefined): import("./types.js").ParallelConfig {
   424	  return {
   425	    enabled: prefs?.parallel?.enabled ?? false,
   426	    max_workers: Math.max(1, Math.min(4, prefs?.parallel?.max_workers ?? 2)),
   427	    budget_ceiling: prefs?.parallel?.budget_ceiling,
   428	    merge_strategy: prefs?.parallel?.merge_strategy ?? "per-milestone",
   429	    auto_merge: prefs?.parallel?.auto_merge ?? "confirm",
   430	  };
   431	}
