   415	function extractPyprojectDependencySections(content: string): string {
   416	  const lines = content.split("\n");
   417	  const collected: string[] = [];
   418	  let section = "";
   419	  let collectingProjectDeps = false;
   420	  let collectingOptionalDeps = false;
   421	  let bracketDepth = 0;
   422	
   423	  for (const line of lines) {
   424	    const trimmed = line.trim();
   425	
   426	    if (collectingProjectDeps) {
   427	      collected.push(line);
   428	      bracketDepth += countChar(line, "[") - countChar(line, "]");
   429	      if (bracketDepth <= 0) {
   430	        collectingProjectDeps = false;
   431	      }
   432	      continue;
   433	    }
   434	
   435	    if (collectingOptionalDeps) {
   436	      collected.push(line);
   437	      bracketDepth += countChar(line, "[") - countChar(line, "]");
   438	      if (bracketDepth <= 0) {
   439	        collectingOptionalDeps = false;
   440	      }
   441	      continue;
   442	    }
   443	
   444	    const sectionMatch = trimmed.match(/^\[([^\]]+)\]$/);
   445	    if (sectionMatch) {
   446	      section = sectionMatch[1].trim();
   447	      continue;
   448	    }
   449	
   450	    if (section === "project" && /^dependencies\s*=\s*\[/.test(trimmed)) {
   451	      collected.push(line);
   452	      bracketDepth = countChar(line, "[") - countChar(line, "]");
   453	      collectingProjectDeps = bracketDepth > 0;
   454	      continue;
   455	    }
   456	
   457	    if (
   458	      section === "project.optional-dependencies" ||
   459	      section === "tool.poetry.dependencies"
   460	    ) {
   461	      if (section === "project.optional-dependencies") {
   462	        const equalsIndex = line.indexOf("=");
   463	        if (equalsIndex !== -1) {
   464	          const value = line.slice(equalsIndex + 1);
   465	          collected.push(value);
   466	          bracketDepth = countChar(value, "[") - countChar(value, "]");
   467	          collectingOptionalDeps = bracketDepth > 0;
   468	        }
   469	      } else {
   470	        collected.push(line);
   471	      }
   472	    }
   473	  }
