   530	function scanProjectFiles(basePath: string): string[] {
   531	  const files: string[] = [];
   532	  const queue: Array<{ path: string; depth: number }> = [{ path: basePath, depth: 0 }];
   533	
   534	  while (queue.length > 0 && files.length < MAX_RECURSIVE_SCAN_FILES) {
   535	    const current = queue.shift()!;
   536	    let entries: Array<{ name: string; isDirectory(): boolean; isFile(): boolean }>;
   537	    try {
   538	      entries = readdirSync(current.path, { withFileTypes: true, encoding: "utf8" });
   539	    } catch {
   540	      continue;
   541	    }
   542	
   543	    for (const entry of entries) {
   544	      const entryPath = join(current.path, entry.name);
   545	      const relativePath = entryPath.slice(basePath.length + 1);
   546	
   547	      if (entry.isDirectory()) {
   548	        if (current.depth < MAX_RECURSIVE_SCAN_DEPTH && !RECURSIVE_SCAN_IGNORED_DIRS.has(entry.name)) {
   549	          queue.push({ path: entryPath, depth: current.depth + 1 });
   550	        }
   551	        continue;
   552	      }
   553	
   554	      if (!entry.isFile()) continue;
   555	      files.push(relativePath);
   556	      if (files.length >= MAX_RECURSIVE_SCAN_FILES) break;
   557	    }
   558	  }
   559	
   560	  return files;
