  });
  if (isolationChoice !== "not_yet") {
    prefs.gitIsolation = isolationChoice as "worktree" | "branch" | "none";
  }
}

// ─── Advanced Preferences Customization ─────────────────────────────────────────

async function customizeAdvancedPrefs(
