            const currentCycle = (this.cycleCounts.get(cycleKey) ?? 0) + 1;
            const maxCycles = config.max_cycles ?? 1;
            if (currentCycle > maxCycles)
                continue;
            this.cycleCounts.set(cycleKey, currentCycle);
            this.activeHook = {
                hookName: config.name,
                triggerUnitType,
                triggerUnitId,
                cycle: currentCycle,
                pendingRetry: false,
